### Traditional Test Setup with beforeEach and afterEach Hooks in JavaScript

Source: https://github.com/microsoft/playwright/blob/main/docs/src/test-fixtures-js.md

Demonstrates the traditional test style using beforeEach and afterEach hooks for test setup and teardown without fixtures. The TodoPage instance is created in beforeEach, populated with initial data, and cleaned up in afterEach. This approach contrasts with the fixture-based pattern by manually managing test state across the test suite.

```javascript
const { test } = require('@playwright/test');
const { TodoPage } = require('./todo-page');

test.describe('todo tests', () => {
  let todoPage;

  test.beforeEach(async ({ page }) => {
    todoPage = new TodoPage(page);
    await todoPage.goto();
    await todoPage.addToDo('item1');
    await todoPage.addToDo('item2');
  });

  test.afterEach(async () => {
    await todoPage.removeAll();
  });

  test('should add an item', async () => {
    await todoPage.addToDo('my item');
    // ...
  });

  test('should remove an item', async () => {
    await todoPage.remove('item1');
    // ...
  });
});
```

